//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 중량단위 바꿨을 때 처리.
//-------------------------------------------------------------------------
scwin.f_UnitChage = async function(flag) {
	// // 벌크일때만....
	var total_cnt = ds_stockPresent.getRowCount();
	var change_unitState = co_acb_unitCd.getValue();  //  "01"-->"TON", "02"-->"KG"

	if (change_unitState == "01") {
		gr_stockPresent.setHeaderValue("stockWt1_header", "중량(Ton)");
		gr_stockPresent.setHeaderValue("stockWt2_header", "중량(Ton)");
		gr_stockPresent.setHeaderValue("stockWt3_header", "중량(Ton)");
		gr_stockPresent.setHeaderValue("stockWt4_header", "중량(Ton)");
		gr_stockPresent.setHeaderValue("stockWtTotal_header", "중량(Ton)");

	} else {
		gr_stockPresent.setHeaderValue("stockWt1_header", "중량(Kg)");
		gr_stockPresent.setHeaderValue("stockWt2_header", "중량(Kg)");
		gr_stockPresent.setHeaderValue("stockWt3_header", "중량(Kg)");
		gr_stockPresent.setHeaderValue("stockWt4_header", "중량(Kg)");
		gr_stockPresent.setHeaderValue("stockWtTotal_header", "중량(Kg)");
	}

	if (flag == 1) {0
		if (change_unitState == "01") {
			for (var i = 0; i < total_cnt; i++) {
				ds_stockPresent.setCellData(i, "stockWt1", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt1") == null ? 0 : String(ds_stockPresent.getCellData(i, "stockWt1")), "KG", "TON"));
				ds_stockPresent.setCellData(i, "stockWt2", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt2") == null ? 0 : String(ds_stockPresent.getCellData(i, "stockWt2")), "KG", "TON"));
				ds_stockPresent.setCellData(i, "stockWt3", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt3") == null ? 0 : String(ds_stockPresent.getCellData(i, "stockWt3")), "KG", "TON"));
				ds_stockPresent.setCellData(i, "stockWt4", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt4") == null ? 0 : String(ds_stockPresent.getCellData(i, "stockWt4")), "KG", "TON"));
				ds_stockPresent.setCellData(i, "stockWtTotal", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWtTotal") == null ? 0 : String(ds_stockPresent.getCellData(i, "stockWtTotal")), "KG", "TON"));
			}
		}
		scwin.cur_unitState = change_unitState;

	} else {
		if (scwin.cur_unitState != change_unitState) {
			for (var i = 0; i < total_cnt; i++) {
                // alert(ds_stockPresent.getCellData(i, "stockWt4"));
				if (change_unitState == "01") {
					ds_stockPresent.setCellData(i, "stockWt1", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt1")), "KG", "TON"));
					ds_stockPresent.setCellData(i, "stockWt2", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt2")), "KG", "TON"));
					ds_stockPresent.setCellData(i, "stockWt3", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt3")), "KG", "TON"));
					ds_stockPresent.setCellData(i, "stockWt4", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt4")), "KG", "TON"));
					ds_stockPresent.setCellData(i, "stockWtTotal", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWtTotal")), "KG", "TON"));
				}
				else {
					ds_stockPresent.setCellData(i, "stockWt1", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt1")), "TON", "KG"));
					ds_stockPresent.setCellData(i, "stockWt2", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt2")), "TON", "KG"));
					ds_stockPresent.setCellData(i, "stockWt3", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt3")), "TON", "KG"));
					ds_stockPresent.setCellData(i, "stockWt4", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt4")), "TON", "KG"));
					ds_stockPresent.setCellData(i, "stockWtTotal", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWtTotal")), "TON", "KG"));
				}
			}
			scwin.cur_unitState = change_unitState;
		}
	}
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {
	if (!$c.gus.cfValidate(tb_mainData)) return;

	scwin.f_validateDate();
};

//------------------------------------------------------
// commit 전에  날짜가 잘 들어가 있는지 검사 한다....
//------------------------------------------------------
scwin.f_validateDate = async function() {
	// 보유기간별로 날짜가 들어가 있는지 확인 하는 Flag
	var chFlag = new Array(4);
	for (i = 0; i < 4; i++) chFlag[i] = false;

	// 보유기간 1
	if (ed_term1From.getValue() != '' && ed_term1To.getValue() != '') {
		if (Number(ed_term1From.getValue()) > Number(ed_term1To.getValue())) {
			$c.win.alert("보유기간 1: 시작일자가 종료일자 이전이어야 합니다.");
			ed_term1From.focus();
			return;
		}
		chFlag[0] = true;
	}

	// 보유기간 2
	if (ed_term2From.getValue() != '' && ed_term2To.getValue() != '') {
		if (Number(ed_term2From.getValue().trim()) > Number(ed_term2To.getValue().trim())) {
			$c.win.alert("보유기간 2: 시작일자가 종료일자 이전이어야 합니다.");
			ed_term2From.focus();
			return;
		}
		chFlag[1] = true;
	}

	// 보유기간 3
	if (ed_term3From.getValue() != '' && ed_term3To.getValue() != '') {
		if (Number(ed_term3From.getValue().trim()) > Number(ed_term3To.getValue().trim())) {
			$c.win.alert("보유기간 3: 시작일자가 종료일자 이전이어야 합니다.");
			ed_term3From.focus();
			return;
		}
		chFlag[2] = true;
	}

	// 보유기간 4
	if (ed_term4From.getValue() != '')
		chFlag[3] = true;

	// 보유기간 1부터 4까지 선행 종료 일자와 후행 시작일자가 중복거나 보유기간이 연속되어 있지 않으면 경고 메시지...
	if (chFlag[0]) {
		if (chFlag[1]) {
			if (Number(ed_term1To.getValue().trim()) >= Number(ed_term2From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 1과 2의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?") != true) return;
			}
			else if (Number(ed_term1To.getValue().trim()) + 1 != Number(ed_term2From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 1과 2의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?") != true) return;
			}
		}
		else if (chFlag[2]) {
			if (Number(ed_term1To.getValue().trim()) >= Number(ed_term3From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 1과 3의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?") != true) return;
			}
			else if (Number(ed_term1To.getValue().trim()) + 1 != Number(ed_term3From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 1과 3의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?") != true) return;
			}
		}
		else if (chFlag[3]) {
			if (Number(ed_term1To.getValue().trim()) > Number(ed_term4From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 1과 4의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?") != true) return;
			}
			else if (Number(ed_term1To.getValue().trim()) + 1 != Number(ed_term4From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 1과 4의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?") != true) return;
			}
		}
	}
	if (chFlag[1]) {
		if (chFlag[2]) {
			if (Number(ed_term2To.getValue().trim()) >= Number(ed_term3From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 2와 3의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?") != true) return;
			}
			else if (Number(ed_term2To.getValue().trim()) + 1 != Number(ed_term3From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 2와 3의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?") != true) return;
			}
		}
		else if (chFlag[3]) {
			if (Number(ed_term2To.getValue().trim()) > Number(ed_term4From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 2와 4의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?") != true) return;
			}
			else if (Number(ed_term2To.getValue().trim()) + 1 != Number(ed_term4From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 2와 4의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?") != true) return;
			}
		}
	}
	if (chFlag[2]) {
		if (chFlag[3]) {
			if (Number(ed_term3To.getValue().trim()) > Number(ed_term4From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 3과 4의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?") != true) return;
			}
			else if (Number(ed_term3To.getValue().trim()) != Number(ed_term4From.getValue().trim())) {
				if (await $c.win.confirm("보유기간 3과 4의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?") != true) return;
			}
		}
	}

	$c.sbm.execute(sbm_retrieve);
};



//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_setDefaultData = function() {
	ed_term1From.setValue("1");
	ed_term1To.setValue("5");
	ed_term2From.setValue("6");
	ed_term2To.setValue("10");
	ed_term3From.setValue("11");
	ed_term3To.setValue("30");
	ed_term4From.setValue("30");

	acb_con_accfCargoStd.setSelectedIndex(0);
	rd_cls.setValue(1);

	scwin.f_clsCondRdoShowHide();
};

////////////////////////////////////////////////
// radio button이 바뀔 때 마다 일어 나는 Action....
////////////////////////////////////////////////
scwin.f_clsCondRdoShowHide = function() {
	if (rd_cls.getValue() == 1)
		acb_con_accfCargoStd.setDisabled(true);
	else if (rd_cls.getValue() == 2)
		acb_con_accfCargoStd.setDisabled(false);
};


///////////////////////////////////////////////
//  컬럼 Show/Hide....
///////////////////////////////////////////////
scwin.f_columnShowHide = function () {

	// 보유기간 1의 컬럼 상태와 컬럼 이름을 설정한다....
    var term1flg = true;
	if (ed_term1From.getValue() == '' || ed_term1To.getValue() == '') {
		term1flg = false;
	}
	gr_stockPresent.setHeaderValue("term1", ed_term1From.getValue() + " ~ " + ed_term1To.getValue() + " 일");
    gr_stockPresent.setColumnVisible("stockQty1", term1flg);
    gr_stockPresent.setColumnVisible("stockWt1", term1flg);
    gr_stockPresent.setColumnVisible("stockCbm1", term1flg);

	// 보유기간 2의 컬럼 상태와 컬럼 이름을 설정한다....
    var term2flg = true;
	if (ed_term2From.getValue() == '' || ed_term2To.getValue() == '') {
		term2flg = false;
	}
	gr_stockPresent.setHeaderValue("term2", ed_term2From.getValue() + " ~ " + ed_term2To.getValue() + " 일");
    gr_stockPresent.setColumnVisible("stockQty2", term2flg);
    gr_stockPresent.setColumnVisible("stockWt2", term2flg);
    gr_stockPresent.setColumnVisible("stockCbm2", term2flg);

	// 보유기간 3의 컬럼 상태와 컬럼 이름을 설정한다....
    var term3flg = true;
	if (ed_term3From.getValue() == '' || ed_term3To.getValue() == '') {
		term3flg = false;
	}
	gr_stockPresent.setHeaderValue("term3", ed_term3From.getValue() + " ~ " + ed_term3To.getValue() + " 일");
    gr_stockPresent.setColumnVisible("stockQty3", term3flg);
    gr_stockPresent.setColumnVisible("stockWt3", term3flg);
    gr_stockPresent.setColumnVisible("stockCbm3", term3flg);

	// 보유기간 4의 컬럼 상태와 컬럼 이름을 설정한다....
    var term4flg = true;
	if (ed_term4From.getValue() == '') {
		term4flg = false;
	}
	gr_stockPresent.setHeaderValue("term4", ed_term4From.getValue() + " 일 초과");
    gr_stockPresent.setColumnVisible("stockQty4", term4flg);
    gr_stockPresent.setColumnVisible("stockWt4", term4flg);
    gr_stockPresent.setColumnVisible("stockCbm4", term4flg);
};

