scwin.sbm_retrieve_submitdone = async function (e) {
    let rowCnt = ds_stockPresent.getRowCount();
	// 데이터가 의미없는 0만 들어올 경우 삭제...
	for(let i = (rowCnt-1) ; i >= 0; i--) {
		if(Number(ds_stockPresent.getCellData(i, 'stockQtyTotal').trim()) == 0 &&
		   Number(ds_stockPresent.getCellData(i, 'stockWtTotal').trim())  == 0 &&
		   Number(ds_stockPresent.getCellData(i, 'stockCbmTotal').trim()) == 0 )
           {
                ds_stockPresent.removeRow(i);
           }
	}

    // ds_stockPresent.reform();
    totalRows.setValue(ds_stockPresent.getRowCount());
    if( ds_stockPresent.getRowCount() == 0 ) {
        await $c.win.alert("조회된 데이터가 없습니다.");
    }

    if(co_acb_unitCd.getValue() == "02") {

        for(let i=0; i <rowCnt; i++) {
            ds_stockPresent.setCellData(i, "stockWt1", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt1")), "TON", "KG"));
            ds_stockPresent.setCellData(i, "stockWt2", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt2")), "TON", "KG"));
            ds_stockPresent.setCellData(i, "stockWt3", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt3")), "TON", "KG"));
            ds_stockPresent.setCellData(i, "stockWt4", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWt4")), "TON", "KG"));
            ds_stockPresent.setCellData(i, "stockWtTotal", await $c.gus.cfConvert2Weight( String(ds_stockPresent.getCellData(i, "stockWtTotal")), "TON", "KG"));
        }

    }

	scwin.f_columnShowHide();
};


